-- SPEC:D.2 — compiled metric view: rto_rate (v1) @ grain=day · entity=semantic_order
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_rto_rate_day AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('day', state_effective_at) AS period,
    channel,
    SUM(CASE WHEN lifecycle_state = 'rto' THEN 1 ELSE 0 END) AS rto_orders,
    SUM(CASE WHEN is_terminal THEN 1 ELSE 0 END) AS terminal_orders
  FROM iceberg.brain_serving.semantic_order
  WHERE state_effective_at IS NOT NULL
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  period,
  channel,
  rto_orders,
  terminal_orders,
  (CAST(rto_orders AS double) / NULLIF(terminal_orders, 0)) AS rto_rate
FROM base;
